#include <bits/stdc++.h>
using namespace std;

int main(){
	string a;
	int cost1=0,cost2=0;
	cin>>a;
	int l=a.size();
	for(int i=0;i<l;i++){
		if(a[i]!='.'){
			if(a[i]=='b'||a[i+1]=='o'||a[i+2]=='y'){
				cost1++;
			}else if(a[i]=='g'||a[i+1]=='i'||a[i+2]=='r'||a[i+3]=='l'){
				cost2++;
			}
		}
	}
	cout<<cost1<<endl;
	cout<<cost2;
	return 0;
}
